def binary_search(n, k):
    if k == 1:
        return 1
    l, r = 1, n
    while l < r:
        mid = l + (r - l) // 2
        if mid * (mid + 1) // 2 <= k:
            l = mid + 1
        else:
            r = mid
    return l


def main():
    n, k = map(int, input().split())
    div = binary_search(n, k)
    if div * (div + 1) // 2 < k:
        print(-1)
    else:
        print(div)


if __name__ == '__main__':
    main()
